UPDATE festival_info 
SET INDEXED_MODIFIED_TIME = #{modified_time}
WHERE content_id = #{content_id}

MERGE INTO festival_info f USING DUAL ON (f.content_id = #{content_id})
WHEN MATCHED THEN UPDATE SET f.title = #{title}, f.addr1 = #{addr1}, f.addr2 = #{addr2}, f.region_code = #{region_code}, f.sigungu_code = #{sigungu_code}, f.first_image = #{first_image}, f.first_image2 = #{first_image2}, f.map_x = #{map_x}, f.map_y = #{map_y}, f.map_level = #{map_level}, f.event_start_date = #{event_start_date}, f.event_end_date = #{event_end_date}, f.modified_time = #{modified_time}, f.overview = #{overview,jdbcType=CLOB}, f.sponsor1_tel = #{sponsor1_tel,jdbcType=VARCHAR}, f.homepage = #{homepage,jdbcType=CLOB}, f.spon_place = #{spon_place,jdbcType=VARCHAR}, f.use_time_festival = #{use_time_festival,jdbcType=VARCHAR}
WHEN NOT MATCHED THEN INSERT ( content_id, title, addr1, addr2, region_code, sigungu_code, first_image, first_image2, map_x, map_y, map_level, event_start_date, event_end_date, created_time, modified_time, overview, sponsor1_tel, homepage, spon_place, use_time_festival ) VALUES ( #{content_id}, #{title}, #{addr1}, #{addr2}, #{region_code}, #{sigungu_code}, #{first_image}, #{first_image2}, #{map_x}, #{map_y}, #{map_level}, #{event_start_date}, #{event_end_date}, #{created_time}, #{modified_time}, #{overview}, #{sponsor1_tel}, #{homepage}, #{spon_place}, #{use_time_festival} )
